import { CommonModule } from "@angular/common";
import { Component, OnInit, inject } from "@angular/core";
import { ActivatedRoute } from "@angular/router";
import { RouterLink } from "@angular/router";
import { AuthService } from "../../services/auth.service";
import { StudentService } from "../../services/student.service";

@Component({
  selector: "app-student-history",
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: "./student-history.component.html",
  styleUrl: "./student-history.component.css"
})
export class StudentHistoryComponent implements OnInit {
  private readonly studentService = inject(StudentService);
  private readonly authService = inject(AuthService);
  private readonly route = inject(ActivatedRoute);

  attempts: any[] = [];
  selectedResult: any = null;
  loading = true;
  errorMessage = "";
  private readonly defaultStudentName = "Student";
  private pendingAttemptId: number | null = null;
  private scopedCourseId: number | null = null;
  private scopedCourseTitle = "";

  ngOnInit(): void {
    const attemptIdParam = Number(this.route.snapshot.queryParamMap.get("attemptId"));
    this.pendingAttemptId = Number.isFinite(attemptIdParam) && attemptIdParam > 0 ? attemptIdParam : null;
    const courseIdParam = Number(this.route.snapshot.queryParamMap.get("courseId"));
    this.scopedCourseId = Number.isFinite(courseIdParam) && courseIdParam > 0 ? courseIdParam : null;
    this.scopedCourseTitle = String(this.route.snapshot.queryParamMap.get("courseTitle") ?? "").trim().toLowerCase();
    this.loadAttempts();
  }

  loadAttempts(): void {
    this.loading = true;
    this.studentService.attempts().subscribe({
      next: (data) => {
        const sorted = [...data].sort((a, b) => {
          const aTime = new Date(a.submittedAt ?? 0).getTime();
          const bTime = new Date(b.submittedAt ?? 0).getTime();
          return bTime - aTime;
        });
        this.attempts = this.applyCourseScope(sorted);
        if (this.pendingAttemptId) {
          this.openResult(this.pendingAttemptId);
          this.pendingAttemptId = null;
        }
        this.loading = false;
      },
      error: (error) => {
        this.errorMessage = error?.error?.message ?? "Failed to load history";
        this.loading = false;
      }
    });
  }

  openResult(attemptId: number): void {
    this.studentService.attemptResult(attemptId).subscribe({
      next: (data) => {
        this.selectedResult = data;
      }
    });
  }

  downloadReport(): void {
    if (!this.selectedResult?.summary) {
      return;
    }

    const summary = this.selectedResult.summary;
    const rows: string[] = [];
    rows.push("Quiz Title,Course,Attempt,Submitted At,Score,Status,Feedback");
    rows.push([
      this.csvCell(summary.quizTitle),
      this.csvCell(summary.courseTitle),
      this.csvCell(summary.attemptNumber),
      this.csvCell(summary.submittedAt),
      this.csvCell(summary.score),
      this.csvCell(summary.passed ? "PASS" : "FAIL"),
      this.csvCell(summary.feedback)
    ].join(","));
    rows.push("");
    rows.push("Question,Type,Student Answer,Correct Answer,Correct,Awarded Points,Max Points");

    const answers: any[] = this.selectedResult.answers ?? [];
    for (const answer of answers) {
      rows.push([
        this.csvCell(answer.prompt),
        this.csvCell(answer.questionType),
        this.csvCell(JSON.stringify(answer.studentAnswer ?? "")),
        this.csvCell(JSON.stringify(answer.correctAnswer ?? "")),
        this.csvCell(answer.correct ? "Yes" : "No"),
        this.csvCell(answer.awardedPoints),
        this.csvCell(answer.maxPoints)
      ].join(","));
    }

    const blob = new Blob([rows.join("\n")], { type: "text/csv;charset=utf-8;" });
    const url = URL.createObjectURL(blob);
    const link = document.createElement("a");
    const fileName = `edusim-attempt-${summary.attemptId}.csv`;
    link.href = url;
    link.download = fileName;
    link.click();
    URL.revokeObjectURL(url);
  }

  studentName(): string {
    const fromSession = this.authService.session()?.fullName;
    if (fromSession) {
      return fromSession;
    }
    const fromSelected = this.selectedResult?.summary?.studentName;
    if (fromSelected) {
      return String(fromSelected);
    }
    return this.defaultStudentName;
  }

  passRateLabel(): string {
    const releasedAttempts = this.attempts.filter((attempt) => attempt.resultReleased !== false);
    if (releasedAttempts.length === 0) {
      return "No released result yet";
    }
    const passCount = releasedAttempts.filter((attempt) => attempt.passed).length;
    const rate = Math.round((passCount / releasedAttempts.length) * 100);
    return `${rate}% pass rate`;
  }

  formatAnswer(value: unknown): string {
    if (value === null || value === undefined) {
      return "-";
    }
    if (typeof value === "string") {
      const trimmed = value.trim();
      return trimmed || "-";
    }
    if (Array.isArray(value)) {
      return value.map((item) => this.formatAnswer(item)).join(", ");
    }
    if (typeof value === "object") {
      return JSON.stringify(value);
    }
    return String(value);
  }

  private csvCell(value: unknown): string {
    const text = String(value ?? "");
    return `"${text.replace(/"/g, "\"\"")}"`;
  }

  private applyCourseScope(rows: any[]): any[] {
    if (!this.scopedCourseId && !this.scopedCourseTitle) {
      return rows;
    }
    return rows.filter((row) => {
      const rowCourseId = Number(row?.courseId ?? 0);
      const rowCourseTitle = String(row?.courseTitle ?? "").trim().toLowerCase();
      if (this.scopedCourseId && rowCourseId === this.scopedCourseId) {
        return true;
      }
      if (this.scopedCourseTitle && rowCourseTitle === this.scopedCourseTitle) {
        return true;
      }
      return false;
    });
  }
}
<div class="container history-shell">
  @if (loading) {
    <p>Loading attempt history...</p>
  } @else if (errorMessage) {
    <p class="error">{{ errorMessage }}</p>
  } @else {
    <section class="panel history-layout">
      <aside class="history-side">
        <section class="profile-card">
          <div class="avatar">{{ studentName().charAt(0) }}</div>
          <div>
            <h2>{{ studentName() }}</h2>
            <p>{{ passRateLabel() }}</p>
          </div>
        </section>

        <nav class="history-menu">
          <a href="javascript:void(0)">My Profile</a>
          <a href="javascript:void(0)">Enrolled Courses</a>
          <a routerLink="/student/history" class="active">My Quiz Attempts</a>
          <a href="javascript:void(0)">Calendar</a>
          <a href="javascript:void(0)">Analytics</a>
          <a routerLink="/student/dashboard">Back to Learning</a>
        </nav>
      </aside>

      <section class="history-main">
        <div class="table-head">
          <div>
            <h1>My Quiz Attempts</h1>
            <p>{{ attempts.length }} records</p>
          </div>
          <button class="btn btn-outline" type="button" routerLink="/student/dashboard">Go Dashboard</button>
        </div>

        @if (attempts.length === 0) {
          <section class="empty-state">
            <p class="muted">No quiz attempt yet.</p>
          </section>
        } @else {
          <section class="attempt-table-wrap">
            <table>
              <thead>
                <tr>
                  <th>Quiz Title</th>
                  <th>Attempt</th>
                  <th>Submitted</th>
                  <th>Score</th>
                  <th>Result</th>
                  <th>Details</th>
                </tr>
              </thead>
              <tbody>
                @for (attempt of attempts; track attempt.attemptId) {
                  <tr>
                    <td>
                      <strong>{{ attempt.quizTitle }}</strong>
                      <div class="muted">{{ attempt.courseTitle }}</div>
                    </td>
                    <td>#{{ attempt.attemptNumber }}</td>
                    <td>{{ attempt.submittedAt | date: "medium" }}</td>
                    <td>{{ attempt.resultReleased === false ? "-" : attempt.score }}</td>
                    <td>
                      @if (attempt.resultReleased === false) {
                        <span class="badge warn">Pending</span>
                      } @else {
                        <span class="badge" [class.fail]="!attempt.passed">
                          {{ attempt.passed ? "Pass" : "Fail" }}
                        </span>
                      }
                    </td>
                    <td>
                      <button class="btn action-btn" type="button" (click)="openResult(attempt.attemptId)">
                        Details
                      </button>
                    </td>
                  </tr>
                }
              </tbody>
            </table>
          </section>
        }

        @if (selectedResult) {
          <section class="result-detail">
            <div class="detail-head">
              <div>
                <h2>{{ selectedResult.summary.quizTitle }}</h2>
                <p class="muted">Feedback: {{ selectedResult.summary.feedback }}</p>
                @if (selectedResult.summary.feedbackViewedAt) {
                  <p class="muted">Last viewed: {{ selectedResult.summary.feedbackViewedAt | date: "medium" }}</p>
                }
                <div class="detail-stats">
                  <span>Score: {{ selectedResult.summary.resultReleased === false ? "-" : (selectedResult.summary.score + "%") }}</span>
                  <span>Time taken: {{ selectedResult.summary.durationSeconds || 0 }}s</span>
                  <span>Submitted: {{ selectedResult.summary.submittedAt | date: "medium" }}</span>
                </div>
              </div>
              @if (selectedResult.resultReleased !== false) {
                <button class="btn btn-outline" type="button" (click)="downloadReport()">Download Score Report</button>
              }
            </div>

            @if (selectedResult.resultReleased === false) {
              <p class="muted">Result will be available after release time.</p>
              @if (selectedResult.releaseAt) {
                <p class="muted">Release time: {{ selectedResult.releaseAt | date: "medium" }}</p>
              }
            } @else {
              <div class="table-scroll">
                <table>
                  <thead>
                    <tr>
                      <th>Question</th>
                      <th>Type</th>
                      <th>Your Answer</th>
                      <th>Correct Answer</th>
                      <th>Explanation</th>
                      <th>Status</th>
                      <th>Points</th>
                    </tr>
                  </thead>
                  <tbody>
                    @for (answer of selectedResult.answers; track answer.questionId) {
                      <tr [class.success-row]="answer.correct" [class.warn-row]="!answer.correct">
                        <td>{{ answer.prompt }}</td>
                        <td>{{ answer.questionType }}</td>
                        <td>{{ formatAnswer(answer.studentAnswer) }}</td>
                        <td>{{ formatAnswer(answer.correctAnswer) }}</td>
                        <td>{{ answer.explanation || "-" }}</td>
                        <td>
                          <span class="badge" [class.fail]="!answer.correct">
                            {{ answer.correct ? "Yes" : "No" }}
                          </span>
                        </td>
                        <td>{{ answer.awardedPoints }} / {{ answer.maxPoints }}</td>
                      </tr>
                    }
                  </tbody>
                </table>
              </div>
            }
          </section>
        }
      </section>
    </section>
  }
</div>
